enter_pin_title = TextObject(bs_BA="Aktiviranje Valet režima", cs_CZ="Aktivován režim Valet", da_DK="Aktiver valet-modus", de_DE="Valet-Modus aktivieren", el_GR="Ενεργοποίηση λειτουργίας παρκαδόρου", en_GB="Activate valet mode", es_ES="Activar modo Valet", fi_FI="Aktivoi valet-tila", fr_FR="Activer le mode voiturier", hr_HR="Aktivirati Valet modus", hu_HU="Valet mód aktiválása", it_IT="Attiva modalità Valet", nl_NL="Valet Modus activeren", no_NO="Aktiver Valet-modus", pl_PL="Aktywuj tryb Valet", pt_PT="Ativar modo Valet", ro_RO="Activare mod valet", ru_RU="Активировать режим Valet", sk_SK="Aktivovať režim Valet", sl_SI="Aktiviranje načina Valet Mode", sr_RS="Aktivirati Valet režim", sv_SE="Aktivera betjänad parkering", tr_TR="Vale modunu etkinleştir", uk_UA="Увімкнути режим Valet")
